1	/**
2	 * Location Details Page
3	 *
4	 * This page displays detailed information for a specific gaming location.
5	 * It acts as a lean wrapper around the LocationsDetailsPageContent component.
6	 *
7	 * @module app/locations/[slug]/page
8	 */
9	
10	export const dynamic = 'force-dynamic';
11	
12	import LocationsDetailsPageContent from '@/components/CMS/locations/LocationsDetailsPageContent';
13	import ProtectedRoute from '@/components/shared/auth/ProtectedRoute';
14	import { MachinesOverviewSkeleton } from '@/components/shared/ui/skeletons/ReportsSkeletons';
15	import { Suspense } from 'react';
16	
17	export default function LocationPage() {
18	  return (
19	    <ProtectedRoute requiredPage="locations">
20	      <Suspense fallback={<MachinesOverviewSkeleton />}>
21	        <LocationsDetailsPageContent />
22	      </Suspense>
23	    </ProtectedRoute>
24	  );
25	}
26

1	/**
2	 * Locations Page Content Component
3	 *
4	 * Main content component that manages locations data, filtering, and rendering.
5	 *
6	 * @module components/locations/LocationsPageContent
7	 */
8	'use client';
9	
10	import LocationsPageFilterSection from '@/components/CMS/locations/LocationsPageFilterSection';
11	import LocationsPageHeaderSection from '@/components/CMS/locations/LocationsPageHeaderSection';
12	import PageLayout from '@/components/shared/layout/PageLayout';
13	import ClientOnly from '@/components/shared/ui/common/ClientOnly';
14	import DateFilters from '@/components/shared/ui/common/DateFilters';
15	import FinancialMetricsCards from '@/components/shared/ui/FinancialMetricsCards';
16	import MachineStatusWidget from '@/components/shared/ui/MachineStatusWidget';
17	import { NoLicenceeAssigned } from '@/components/shared/ui/NoLicenceeAssigned';
18	import PaginationControls from '@/components/shared/ui/PaginationControls';
19	import { useLocationsPageData } from '@/lib/hooks/locations/useLocationsPageData';
20	import { useCurrencyFormat } from '@/lib/hooks/useCurrencyFormat';
21	import { useDashBoardStore } from '@/lib/store/dashboardStore';
22	import { useLocationsActionsStore } from '@/lib/store/locationActionsStore';
23	import { useUserStore } from '@/lib/store/userStore';
24	import type { AggregatedLocation } from '@/shared/types';
25	import { formatCurrencyWithCodeString } from '@/lib/utils/currency';
26	import { shouldShowNoLicenceeMessage } from '@/lib/utils/licencee';
27	import axios from 'axios';
28	import { useRouter } from 'next/navigation';
29	import { useMemo, useState } from 'react';
30	import { toast } from 'sonner';
31	import LocationsLocationCard from './LocationsLocationCard';
32	import LocationsLocationSkeleton from './LocationsLocationSkeleton';
33	import LocationsArchivedLocationSkeleton from './LocationsArchivedLocationSkeleton';
34	import LocationsLocationTable from './LocationsLocationTable';
35	import LocationsDeleteLocationModal from './modals/LocationsDeleteLocationModal';
36	import LocationsEditLocationModal from './modals/LocationsEditLocationModal';
37	import LocationsNewLocationModal from './modals/LocationsNewLocationModal';
38	
39	export default function LocationsPageContent() {
40	  // ============================================================================
41	  // State & Hooks
42	  // ============================================================================
43	  const router = useRouter();
44	  const { user } = useUserStore();
45	  const { selectedLicencee, setSelectedLicencee } = useDashBoardStore();
46	  const { openEditModal, openDeleteModal, closeDeleteModal } =
47	    useLocationsActionsStore();
48	  const [isNewModalOpen, setIsNewModalOpen] = useState(false);
49	
50	  // Custom hook for locations page data and logic
51	  const locationsPageData = useLocationsPageData();
52	  const { displayCurrency } = useCurrencyFormat();
53	
54	  const {
55	    loading,
56	    refreshing,
57	    locationData,
58	    financialTotals,
59	    metricsTotals,
60	    metricsTotalsLoading,
61	    machineStats,
62	    machineStatsLoading,
63	    membershipStats,
64	    membershipStatsLoading,
65	    selectedFilters,
66	    searchTerm,
67	    currentPage,
68	    totalPages,
69	    handleRefresh,
70	    handleFilterChange,
71	    handleMultiFilterChange,
72	    setSearchTerm,
73	    setCurrentPage,
74	    hasMoreLocations,
75	    isDataComplete,
76	  } = locationsPageData;
77	
78	  // ============================================================================
79	  // Computed
80	  // ============================================================================
81	  /**
82	   * Check if the current user can manage (create/edit/delete) locations.
83	   * Only developers, admins, managers, and location admins can manage locations.
84	   */
85	  const canManageLocations = useMemo(() => {
86	    const roles = user?.roles || [];
87	    return ['developer', 'owner', 'admin', 'manager', 'location admin'].some(
88	      r => roles.includes(r)
89	    );
90	  }, [user]);
91	
92	  const canPermanentlyDelete = useMemo(() => {
93	    const roles = user?.roles || [];
94	    return ['developer', 'owner', 'admin', 'location admin'].some(r =>
95	      roles.map((role: string) => role.toLowerCase()).includes(r)
96	    );
97	  }, [user]);
98	
99	  // ============================================================================
100	  // Handlers
101	  // ============================================================================
102	  /**
103	   * Navigate to a specific location's detail page.
104	   */
105	  const handleLocationClick = (locationId: string) => {
106	    if (locationId) {
107	      router.push(`/locations/${locationId}`);
108	    }
109	  };
110	
111	  /**
112	   * Restore an archived location back to active status.
113	   */
114	  const handleRestore = async (location: Partial<AggregatedLocation>) => {
115	    const loc = location as Record<string, unknown>;
116	    const locationId = loc.location as string;
117	    const locationName = loc.locationName as string;
118	    if (!locationId) return;
119	
120	    try {
121	      await axios.patch('/api/locations', {
122	        id: locationId,
123	        action: 'restore',
124	      });
125	      toast.success(`${locationName || 'Location'} restored successfully`);
126	      handleRefresh();
127	    } catch {
128	      toast.error('Failed to restore location');
129	    }
130	  };
131	
132	  // ============================================================================
133	  // Render
134	  // ============================================================================
135	  // If user has no licencee assigned, show the "No Licencee Assigned" message
136	  if (shouldShowNoLicenceeMessage(user)) {
137	    return <NoLicenceeAssigned />;
138	  }
139	
140	  return (
141	    <>
142	      {/* Modal Components for CRUD operations */}
143	      <LocationsDeleteLocationModal
144	        onDelete={() => {
145	          handleRefresh();
146	          closeDeleteModal();
147	        }}
148	      />
149	      <LocationsEditLocationModal onLocationUpdated={handleRefresh} />
150	      <LocationsNewLocationModal
151	        isOpen={isNewModalOpen}
152	        onClose={() => setIsNewModalOpen(false)}
153	        onCreated={handleRefresh}
154	      />
155	
156	      <PageLayout
157	        headerProps={{ selectedLicencee, setSelectedLicencee }}
158	        mainClassName="flex flex-col flex-1 px-2 py-4 sm:p-6 w-full max-w-full"
159	        onRefresh={handleRefresh}
160	        refreshing={refreshing}
161	      >
162	        {/* Page Header: Title and primary actions */}
163	        <LocationsPageHeaderSection
164	          refreshing={refreshing}
165	          canManage={canManageLocations}
166	          onRefresh={handleRefresh}
167	          onNew={() => setIsNewModalOpen(true)}
168	        />
169	
170	        {/* Financial Performance Summary Cards */}
171	        <div className="mt-6">
172	          <FinancialMetricsCards
173	            totals={
174	              isDataComplete && !metricsTotalsLoading
175	                ? financialTotals
176	                : metricsTotals || financialTotals
177	            }
178	            loading={loading || metricsTotalsLoading}
179	            title="Total for all Locations"
180	          />
181	        </div>
182	
183	        {/* Filters and Status Section */}
184	        <div className="flex flex-col gap-4">
185	          {/* Date range picker and machine status indicator */}
186	          <div className="mt-4 flex flex-col justify-between gap-4 xl:flex-row xl:items-center">
187	            <div className="order-1 w-auto flex-shrink-0">
188	              <DateFilters hideAllTime />
189	            </div>
190	            <div className="order-2 w-auto">
191	              <MachineStatusWidget
192	                isLoading={
193	                  machineStatsLoading ||
194	                  membershipStatsLoading ||
195	                  machineStats === null
196	                }
197	                title="Location Status"
198	                onlineLabel="Online Locations"
199	                offlineLabel="Offline Locations"
200	                onlineCount={machineStats?.onlineLocations || 0}
201	                offlineCount={machineStats?.offlineLocations || 0}
202	                totalCount={machineStats?.totalLocations}
203	                membershipCount={membershipStats?.membershipCount || 0}
204	                showTotal
205	                showMembership
206	              />
207	            </div>
208	          </div>
209	
210	          {/* Search bar and multi-filter dropdowns */}
211	          <LocationsPageFilterSection
212	            searchTerm={searchTerm}
213	            onSearchChange={setSearchTerm}
214	            selectedFilters={selectedFilters}
215	            onFilterChange={handleFilterChange}
216	            onMultiFilterChange={handleMultiFilterChange}
217	            selectedStatus={locationsPageData.selectedStatus}
218	            onStatusChange={locationsPageData.setSelectedStatus}
219	          />
220	        </div>
221	
222	        {/* ============================================================================
223	           Locations Listing: Responsive card/table view
224	           ============================================================================ */}
225	        <div className="mt-4 flex-1 lg:mt-0">
226	          {/* Show loading skeletons while data is being fetched */}
227	          {loading ? (
228	            <div>
229	              {locationsPageData.selectedStatus === 'Archived' ? (
230	                <ClientOnly fallback={<LocationsArchivedLocationSkeleton />}>
231	                  {/* Mobile skeletons */}
232	                  <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:hidden">
233	                    {[...Array(20)].map((_, i) => (
234	                      <LocationsArchivedLocationSkeleton key={i} />
235	                    ))}
236	                  </div>
237	                  {/* Desktop table skeleton */}
238	                  <div className="hidden lg:block">
239	                    <LocationsArchivedLocationSkeleton />
240	                  </div>
241	                </ClientOnly>
242	              ) : (
243	                <ClientOnly fallback={<LocationsLocationSkeleton />}>
244	                  {/* Mobile skeletons */}
245	                  <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:hidden">
246	                    {[...Array(20)].map((_, i) => (
247	                      <LocationsLocationSkeleton key={i} />
248	                    ))}
249	                  </div>
250	                  {/* Desktop table skeleton */}
251	                  <div className="hidden lg:block">
252	                    <LocationsLocationSkeleton />
253	                  </div>
254	                </ClientOnly>
255	              )}
256	            </div>
257	          ) : /* Show empty state message if no locations match the filters */
258	          locationData.length === 0 ? (
259	            <div className="py-12 text-center text-gray-500">
260	              No locations found matching your criteria.
261	            </div>
262	          ) : (
263	            /* Main Content: Display data in appropriate format for viewport */
264	            <div>
265	              {/* Mobile View: Cards display */}
266	              <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:hidden">
267	                {locationData.map(loc => (
268	                  <LocationsLocationCard
269	                    key={String(loc._id || loc.location || Math.random())}
270	                    location={loc}
271	                    onLocationClick={handleLocationClick}
272	                    onEdit={location => openEditModal(location)}
273	                    onDelete={location => openDeleteModal(location)}
274	                    onRestore={location => handleRestore(location)}
275	                    showArchived={
276	                      locationsPageData.selectedStatus === 'Archived'
277	                    }
278	                    canManageLocations={canManageLocations}
279	                    canPermanentlyDelete={canPermanentlyDelete}
280	                  />
281	                ))}
282	              </div>
283	
284	              {/* Desktop View: Interactive data table */}
285	              <div className="hidden overflow-x-auto border border-gray-200 bg-white shadow-sm lg:block">
286	                <LocationsLocationTable
287	                  locations={locationData}
288	                  onLocationClick={handleLocationClick}
289	                  showArchived={locationsPageData.selectedStatus === 'Archived'}
290	                  canManageLocations={canManageLocations}
291	                  canPermanentlyDelete={canPermanentlyDelete}
292	                  onAction={(action, loc) => {
293	                    if (action === 'edit') openEditModal(loc);
294	                    if (action === 'delete') openDeleteModal(loc);
295	                    if (action === 'restore') handleRestore(loc);
296	                  }}
297	                  onSort={locationsPageData.handleSort}
298	                  sortOption={locationsPageData.sortOption}
299	                  sortOrder={locationsPageData.sortOrder}
300	                  formatCurrency={amount =>
301	                    formatCurrencyWithCodeString(amount, displayCurrency)
302	                  }
303	                />
304	              </div>
305	
306	              {/* Data Pagination Controls */}
307	              <PaginationControls
308	                currentPage={currentPage}
309	                totalPages={totalPages}
310	                setCurrentPage={setCurrentPage}
311	                hasMore={hasMoreLocations}
312	              />
313	            </div>
314	          )}
315	        </div>
316	      </PageLayout>
317	    </>
318	  );
319	}
