1	/**
2	 * Locations Details Page Content Component
3	 *
4	 * Handles all state management and data fetching for the location details page.
5	 *
6	 * Features:
7	 * - Machine listing with card (mobile) and table (desktop) views
8	 * - Search and filter capabilities
9	 * - Financial metrics overview
10	 * - Machine status widget
11	 * - Create, edit, and delete machines (role-based)
12	 * - Pagination
13	 * - Responsive design for mobile and desktop
14	 */
15	
16	'use client';
17	
18	import PageLayout from '@/components/shared/layout/PageLayout';
19	import { useCallback, useEffect, useRef, useState } from 'react';
20	
21	import CabinetsDeleteCabinetModal from '@/components/CMS/cabinets/modals/CabinetsDeleteCabinetModal';
22	import CabinetsEditCabinetModal from '@/components/CMS/cabinets/modals/CabinetsEditCabinetModal';
23	import CabinetsNewCabinetModal from '@/components/CMS/cabinets/modals/CabinetsNewCabinetModal';
24	import LocationsDetailsCabinetsSection from '@/components/CMS/locations/sections/LocationsDetailsCabinetsSection';
25	import { useLocationCabinetsData } from '@/lib/hooks/locations/useLocationCabinetsData';
26	import { useLocationChartData } from '@/lib/hooks/locations/useLocationChartData';
27	import {
28	  canEditMachines,
29	  canManageLocations,
30	  canViewArchivedMachines,
31	  hasAdminAccess,
32	  UserRole,
33	} from '@/lib/utils/permissions';
34	import { useParams, useRouter, useSearchParams } from 'next/navigation';
35	
36	import { useLocationsActionsStore } from '@/lib/store/locationActionsStore';
37	import LocationsEditLocationModal from './modals/LocationsEditLocationModal';
38	
39	import LocationsDetailsMembersSection from '@/components/CMS/locations/sections/LocationsDetailsMembersSection';
40	import { MembersHandlersProvider } from '@/components/CMS/members/context/MembersHandlersContext';
41	import { MEMBERS_TABS_CONFIG } from '@/lib/constants';
42	import {
43	  useLocationMachineStats,
44	  useLocationMembershipStats,
45	} from '@/lib/hooks/data';
46	import { useUserStore, type UserStore } from '@/lib/store/userStore';
47	import { useMembersNavigation } from '@/lib/hooks/navigation';
48	import type { AggregatedLocation } from '@/shared/types';
49	import { useDashBoardStore } from '@/lib/store/dashboardStore';
50	import { useNewCabinetStore } from '@/lib/store/newCabinetStore';
51	import LocationsDetailsHeader from './details/LocationsDetailsHeader';
52	import LocationsDetailsViewToggle from './details/LocationsDetailsViewToggle';
53	import type { GamingMachine as Cabinet } from '@/shared/types/entities';
54	
55	/**
56	 * Locations Details Page Content Component
57	 */
58	export default function LocationsDetailsPageContent() {
59	  // ============================================================================
60	  // State & Hooks
61	  // ============================================================================
62	  const params = useParams();
63	  const router = useRouter();
64	  const searchParams = useSearchParams();
65	  const locationId = params.slug as string;
66	  const tabParam = searchParams.get('tab');
67	
68	  const {
69	    selectedLicencee,
70	    setSelectedLicencee,
71	    activeMetricsFilter,
72	    customDateRange,
73	  } = useDashBoardStore();
74	
75	  const user = useUserStore((state: UserStore) => state.user);
76	
77	  const [dateFilterInitialized, setDateFilterInitialized] = useState(false);
78	  const [filtersInitialized, setFiltersInitialized] = useState(false);
79	
80	  // View Toggle State - checks URL param first, defaults to machines
81	  const [activeView, setActiveView] = useState<'machines' | 'members'>(
82	    tabParam === 'members' ? 'members' : 'machines'
83	  );
84	
85	  const cabinetsData = useLocationCabinetsData({
86	    locationId,
87	    selectedLicencee,
88	    activeMetricsFilter,
89	    customDateRange,
90	    dateFilterInitialized,
91	    filtersInitialized,
92	    isAdminUser: hasAdminAccess((user?.roles || []) as UserRole[]),
93	    setDateFilterInitialized,
94	    setFiltersInitialized,
95	  });
96	
97	  const chartDataHook = useLocationChartData({
98	    locationId,
99	    selectedLicencee,
100	    activeMetricsFilter: activeMetricsFilter || null,
101	    customDateRange,
102	    activeView,
103	    status: cabinetsData.selectedStatus,
104	    gameType: cabinetsData.selectedGameType,
105	    searchTerm: cabinetsData.debouncedSearchTerm,
106	    includeArchived: cabinetsData.showArchived,
107	  });
108	
109	  // Machine status stats from dedicated API (location-specific)
110	  const { machineStats, machineStatsLoading, refreshMachineStats } =
111	    useLocationMachineStats(
112	      locationId,
113	      cabinetsData.selectedGameType === 'all'
114	        ? undefined
115	        : cabinetsData.selectedGameType,
116	      cabinetsData.searchTerm
117	    );
118	  const { membershipStats, membershipStatsLoading, refreshMembershipStats } =
119	    useLocationMembershipStats(locationId);
120	
121	  // Members Tab Navigation
122	  // Disable URL sync for location details page to prevent conflicts
123	  const { activeTab, handleTabClick } = useMembersNavigation(
124	    MEMBERS_TABS_CONFIG,
125	    true
126	  );
127	
128	  const membersRefreshHandlerRef = useRef<(() => void) | undefined>(undefined);
129	
130	  const { openCabinetModal } = useNewCabinetStore();
131	  const { openEditModal } = useLocationsActionsStore();
132	
133	  // ============================================================================
134	  // Computed
135	  // ============================================================================
136	  const userRoles = (user?.roles || []) as UserRole[];
137	  const isAdminUser = hasAdminAccess(userRoles);
138	  const canManageMachines = canEditMachines(userRoles);
139	  const canEditLocation = canManageLocations(userRoles);
140	  const canViewArchived = canViewArchivedMachines(userRoles);
141	  const canPermanentlyDelete = isAdminUser || userRoles.includes('developer');
142	
143	  // Determine if Members tab should be shown
144	  // Show if feature enabled AND (has members OR stats are still loading)
145	  const showMembersTab = !!(
146	    cabinetsData.locationMembershipEnabled &&
147	    (membershipStatsLoading ||
148	      (membershipStats && membershipStats.membershipCount > 0))
149	  );
150	
151	  // ============================================================================
152	  // Effects
153	  // ============================================================================
154	
155	  // Sync state with URL parameter
156	  useEffect(() => {
157	    if (tabParam === 'members') {
158	      setActiveView('members');
159	    } else {
160	      setActiveView('machines');
161	    }
162	  }, [tabParam]);
163	
164	  // If we are on members tab but it should be hidden (and not loading), redirect to machines
165	  useEffect(() => {
166	    if (
167	      activeView === 'members' &&
168	      !membershipStatsLoading &&
169	      membershipStats &&
170	      membershipStats.membershipCount === 0 &&
171	      cabinetsData.locationMembershipEnabled
172	    ) {
173	      // If user manually navigated to ?tab=members but there are no members, switch back
174	      handleViewChange('machines');
175	    }
176	  }, [
177	    activeView,
178	    membershipStatsLoading,
179	    membershipStats,
180	    cabinetsData.locationMembershipEnabled,
181	  ]);
182	
183	  // Detect when date filter is properly initialized
184	  useEffect(() => {
185	    if (activeMetricsFilter) {
186	      setDateFilterInitialized(true);
187	    }
188	  }, [activeMetricsFilter]);
189	
190	  // ============================================================================
191	  // Handlers
192	  // ============================================================================
193	  const handleFilterChange = (status: string) => {
194	    cabinetsData.setSelectedStatus(status);
195	  };
196	
197	  const handleViewChange = (view: 'machines' | 'members') => {
198	    setActiveView(view);
199	
200	    // Create new URLSearchParams to preserve other params if they exist (though currently none strictly needed)
201	    const newParams = new URLSearchParams(searchParams.toString());
202	
203	    if (view === 'members') {
204	      newParams.set('tab', 'members');
205	    } else {
206	      newParams.delete('tab');
207	    }
208	
209	    // Construct new path
210	    const newPath = `?${newParams.toString()}`;
211	    router.push(newPath);
212	  };
213	
214	  // Refresh handler
215	  const handleRefresh = useCallback(async () => {
216	    // If members view is active, trigger members refresh handler
217	    if (activeView === 'members' && membersRefreshHandlerRef.current) {
218	      membersRefreshHandlerRef.current();
219	      return;
220	    }
221	
222	    // Only refresh machines/charts if on machines view
223	    if (activeView !== 'machines') {
224	      return;
225	    }
226	
227	    // Refresh location document (re-runs SMIB auto-tag + updates locationData)
228	    await cabinetsData.refreshLocation();
229	    // Refresh machine status and membership stats
230	    await Promise.all([refreshMachineStats(), refreshMembershipStats()]);
231	    // Refresh cabinets data (hook handles the refresh)
232	    await cabinetsData.refreshCabinets();
233	    // Refresh chart data
234	    chartDataHook.refreshChart();
235	  }, [
236	    activeView,
237	    refreshMachineStats,
238	    refreshMembershipStats,
239	    cabinetsData,
240	    chartDataHook,
241	  ]);
242	
243	  // Custom range handler — does NOT call refreshCabinets() because the
244	  // useLocationCabinetsData effect already re-fetches when filters change.
245	  // Calling refreshCabinets() here caused a race condition where
246	  // refreshCabinets() cleared prevCabinetsFetchKey while the effect's fetch
247	  // was in-flight, preventing the finally block from turning off loading.
248	  const handleCustomRangeGo = useCallback(async () => {
249	    if (activeView !== 'machines') return;
250	
251	    await cabinetsData.refreshLocation();
252	    await Promise.all([refreshMachineStats(), refreshMembershipStats()]);
253	    chartDataHook.refreshChart();
254	  }, [
255	    activeView,
256	    refreshMachineStats,
257	    refreshMembershipStats,
258	    cabinetsData,
259	    chartDataHook,
260	  ]);
261	
262	  // Refresh machine stats when date filters change
263	  useEffect(() => {
264	    if (
265	      activeView === 'machines' &&
266	      activeMetricsFilter &&
267	      dateFilterInitialized
268	    ) {
269	      refreshMachineStats();
270	    }
271	  }, [
272	    activeMetricsFilter,
273	    customDateRange,
274	    activeView,
275	    dateFilterInitialized,
276	    refreshMachineStats,
277	  ]);
278	
279	  /**
280	   * Restores a soft-deleted cabinet by clearing its deletedAt field.
281	   */
282	  const handleRestoreCabinet = async (cabinet: Cabinet) => {
283	    if (
284	      !confirm(
285	        `Are you sure you want to restore machine ${cabinet.serialNumber || cabinet.custom?.name || 'N/A'}?`
286	      )
287	    ) {
288	      return;
289	    }
290	
291	    try {
292	      const response = await fetch(
293	        `/api/locations/${locationId}/cabinets/${cabinet._id}`,
294	        {
295	          method: 'PATCH',
296	          headers: {
297	            'Content-Type': 'application/json',
298	          },
299	          body: JSON.stringify({ action: 'restore' }),
300	        }
301	      );
302	
303	      const result = await response.json();
304	      if (result.success) {
305	        import('sonner').then(({ toast }) =>
306	          toast.success('Machine restored successfully')
307	        );
308	        handleRefresh();
309	      } else {
310	        import('sonner').then(({ toast }) =>
311	          toast.error(result.error || 'Failed to restore machine')
312	        );
313	      }
314	    } catch (error) {
315	      console.error('Error restoring cabinet:', error);
316	      import('sonner').then(({ toast }) =>
317	        toast.error('An error occurred during restoration')
318	      );
319	    }
320	  };
321	
322	  /**
323	   * Permanently deletes a cabinet from the database.
324	   * This action is restricted to admins and developers.
325	   */
326	  const handlePermanentDeleteCabinet = async (cabinet: Cabinet) => {
327	    if (
328	      !confirm(
329	        `CRITICAL: Are you sure you want to PERMANENTLY delete machine ${cabinet.serialNumber || cabinet.custom?.name || 'N/A'}? This action cannot be undone.`
330	      )
331	    ) {
332	      return;
333	    }
334	
335	    try {
336	      const response = await fetch(
337	        `/api/locations/${locationId}/cabinets/${cabinet._id}?hardDelete=true`,
338	        {
339	          method: 'DELETE',
340	        }
341	      );
342	
343	      const result = await response.json();
344	      if (result.success) {
345	        import('sonner').then(({ toast }) =>
346	          toast.success('Machine permanently deleted')
347	        );
348	        handleRefresh();
349	      } else {
350	        import('sonner').then(({ toast }) =>
351	          toast.error(result.error || 'Failed to delete machine permanently')
352	        );
353	      }
354	    } catch (error) {
355	      console.error('Error permanently deleting cabinet:', error);
356	      import('sonner').then(({ toast }) =>
357	        toast.error('An error occurred during permanent deletion')
358	      );
359	    }
360	  };
361	
362	  // ============================================================================
363	  // Render
364	  // ============================================================================
365	  return (
366	    <>
367	      <PageLayout
368	        headerProps={{
369	          selectedLicencee,
370	          setSelectedLicencee,
371	          disabled:
372	            cabinetsData.loading ||
373	            cabinetsData.cabinetsLoading ||
374	            cabinetsData.refreshing,
375	        }}
376	        hideOptions={true}
377	        hideLicenceeFilter={true}
378	        mainClassName="flex flex-col flex-1 px-2 py-4 sm:p-6 w-full max-w-full"
379	        showToaster={false}
380	        onRefresh={handleRefresh}
381	        refreshing={cabinetsData.refreshing}
382	      >
383	        {/* Header Section: Title, back button, and action buttons */}
384	        <LocationsDetailsHeader
385	          locationId={locationId}
386	          locationData={cabinetsData.locationData as AggregatedLocation}
387	          refreshing={cabinetsData.refreshing}
388	          activeView={activeView}
389	          canManageMachines={canManageMachines}
390	          onRefresh={handleRefresh}
391	          onEditLocation={loc => {
392	            if (canEditLocation) {
393	              openEditModal(loc);
394	            }
395	          }}
396	          onNewMachine={openCabinetModal}
397	        />
398	
399	        {/* View Toggle */}
400	        <LocationsDetailsViewToggle
401	          activeView={activeView}
402	          showMembersTab={showMembersTab}
403	          onViewChange={handleViewChange}
404	        />
405	
406	        {activeView === 'members' ? (
407	          <MembersHandlersProvider>
408	            <LocationsDetailsMembersSection
409	              locationId={locationId}
410	              locationName={cabinetsData.locationName}
411	              selectedLicencee={selectedLicencee}
412	              activeTab={activeTab}
413	              handleTabClick={handleTabClick}
414	              onRefreshReady={handler => {
415	                membersRefreshHandlerRef.current = handler;
416	              }}
417	            />
418	          </MembersHandlersProvider>
419	        ) : (
420	          <LocationsDetailsCabinetsSection
421	            financialTotals={cabinetsData.financialTotals}
422	            chartData={chartDataHook.chartData}
423	            filteredCabinets={cabinetsData.filteredCabinets}
424	            gameTypes={cabinetsData.gameTypes}
425	            locationName={cabinetsData.locationName}
426	            locationId={locationId}
427	            selectedLocationId={cabinetsData.selectedLocationId}
428	            locations={cabinetsData.locations}
429	            error={cabinetsData.error}
430	            loading={cabinetsData.loading}
431	            cabinetsLoading={cabinetsData.cabinetsLoading}
432	            loadingChartData={chartDataHook.loadingChartData}
433	            machineStatsLoading={machineStatsLoading}
434	            membershipStatsLoading={membershipStatsLoading}
435	            showGranularitySelector={chartDataHook.showGranularitySelector}
436	            chartGranularity={chartDataHook.chartGranularity}
437	            availableGranularityOptions={
438	              chartDataHook.availableGranularityOptions
439	            }
440	            activeMetricsFilter={activeMetricsFilter}
441	            searchTerm={cabinetsData.searchTerm}
442	            selectedStatus={cabinetsData.selectedStatus}
443	            selectedGameType={cabinetsData.selectedGameType}
444	            selectedSmibStatus={cabinetsData.selectedSmibStatus}
445	            sortOption={cabinetsData.sortOption}
446	            sortOrder={cabinetsData.sortOrder}
447	            currentPage={cabinetsData.currentPage}
448	            effectiveTotalPages={cabinetsData.effectiveTotalPages}
449	            totalCount={cabinetsData.totalCount}
450	            debouncedSearchTerm={cabinetsData.debouncedSearchTerm || ''}
451	            machineStats={machineStats}
452	            membershipStats={membershipStats}
453	            setSearchTerm={cabinetsData.setSearchTerm}
454	            setSelectedStatus={cabinetsData.setSelectedStatus}
455	            setSelectedGameType={cabinetsData.setSelectedGameType}
456	            setSelectedSmibStatus={cabinetsData.setSelectedSmibStatus}
457	            setSortOption={cabinetsData.setSortOption}
458	            setSortOrder={cabinetsData.setSortOrder}
459	            setCurrentPage={cabinetsData.setCurrentPage}
460	            setChartGranularity={chartDataHook.setChartGranularity}
461	            setSelectedLocationId={cabinetsData.setSelectedLocationId}
462	            handleRefresh={handleRefresh}
463	            onCustomRangeGo={handleCustomRangeGo}
464	            includeJackpot={cabinetsData.includeJackpot}
465	            handleFilterChange={handleFilterChange}
466	            showArchived={cabinetsData.showArchived}
467	            setShowArchived={cabinetsData.setShowArchived}
468	            canViewArchived={canViewArchived}
469	            onRestore={handleRestoreCabinet}
470	            onPermanentDelete={handlePermanentDeleteCabinet}
471	            canPermanentlyDeleteMachines={canPermanentlyDelete}
472	            handleLocationChangeInPlace={(newLocationId: string) => {
473	              if (newLocationId === 'all') {
474	                router.push('/locations');
475	                return;
476	              }
477	              router.push(`/locations/${newLocationId}`);
