1	/**
2	 * useLocationsPageData Hook
3	 *
4	 * Coordinates all data, filtering, and UI state for the locations dashboard.
5	 *
6	 * Features:
7	 * - Location data fetching with batch accumulation
8	 * - Search with frontend first, backend fallback
9	 * - Financial metrics and machine status coordination
10	 * - Pagination state management
11	 * - Filter initialization handling
12	 */
13	
14	'use client';
15	
16	import { fetchDashboardTotals } from '@/lib/helpers/dashboard';
17	import {
18	  useLocationData,
19	  useLocationMachineStats,
20	  useLocationMembershipStats,
21	} from '@/lib/hooks/data';
22	import { useAbortableRequest } from '@/lib/hooks/useAbortableRequest';
23	import { useCurrencyFormat } from '@/lib/hooks/useCurrencyFormat';
24	import { useDashBoardStore } from '@/lib/store/dashboardStore';
25	import type { DashboardTotals } from '@/lib/types';
26	import type { LocationFilter, LocationSortOption } from '@/lib/types/location';
27	import { isAbortError } from '@/lib/utils/errors';
28	import { calculateLocationFinancialTotals } from '@/lib/utils/financial';
29	import { useDebounce } from '@/lib/utils/hooks';
30	import { useCallback, useEffect, useMemo, useState } from 'react';
31	import axios from 'axios';
32	
33	type SmibSyncStatus = {
34	  lastSync: Date | null;
35	  isStale: boolean;
36	  staleAfterHours: number;
37	};
38	
39	export function useLocationsPageData() {
40	  const { selectedLicencee, activeMetricsFilter, customDateRange } =
41	    useDashBoardStore();
42	  const { displayCurrency } = useCurrencyFormat();
43	
44	  // ============================================================================
45	  // State & Hooks
46	  // ============================================================================
47	  const [selectedFilters, setSelectedFilters] = useState<LocationFilter[]>([]);
48	  const [selectedStatus, setSelectedStatus] = useState<string>('all');
49	  const [searchTerm, setSearchTerm] = useState('');
50	  const debouncedSearchTerm = useDebounce(searchTerm, 500);
51	
52	  const [refreshing, setRefreshing] = useState(false);
53	  const [currentPage, setCurrentPage] = useState(0);
54	  const [metricsTotals, setMetricsTotals] = useState<DashboardTotals | null>(
55	    null
56	  );
57	  const [metricsTotalsLoading, setMetricsTotalsLoading] = useState(true);
58	  const [filtersInitialized, setFiltersInitialized] = useState(false);
59	
60	  // Sorting State
61	  const [sortOption, setSortOption] = useState<LocationSortOption>('default');
62	  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
63	
64	  // SMIB Sync State
65	  const [smibSyncStatus, _setSmibSyncStatus] = useState<SmibSyncStatus | null>(
66	    null
67	  );
68	  const [hasCheckedSmibSync, setHasCheckedSmibSync] = useState(false);
69	
70	  const makeMetricsRequest = useAbortableRequest();
71	
72	  // ============================================================================
73	  // Pagination Constants
74	  // ============================================================================
75	  const ITEMS_PER_PAGE = 20;
76	  const ITEMS_PER_BATCH = 100;
77	  const PAGES_PER_BATCH = ITEMS_PER_BATCH / ITEMS_PER_PAGE; // 5
78	
79	  const [loadedBatches, setLoadedBatches] = useState<Set<number>>(new Set());
80	
81	  // Helper to calculate which batch a page belongs to
82	  const calculateBatchNumber = useCallback((page: number) => {
83	    return Math.floor(page / PAGES_PER_BATCH) + 1;
84	  }, []);
85	
86	  // ============================================================================
87	  // Base Hook Integration
88	  // ============================================================================
89	  const { locationData, loading, searchLoading, error, fetchData, totalCount } =
90	    useLocationData({
91	      selectedLicencee,
92	      activeMetricsFilter,
93	      customDateRange,
94	      searchTerm,
95	      selectedFilters,
96	      selectedStatus,
97	      sortBy: sortOption,
98	      sortOrder: sortOrder,
99	    });
100	
101	  const machineTypeFilterString = useMemo(
102	    () => selectedFilters.join(','),
103	    [selectedFilters]
104	  );
105	  const { machineStats, machineStatsLoading, refreshMachineStats } =
106	    useLocationMachineStats(
107	      undefined,
108	      machineTypeFilterString,
109	      debouncedSearchTerm,
110	      undefined,
111	      selectedStatus
112	    );
113	  const { membershipStats, membershipStatsLoading, refreshMembershipStats } =
114	    useLocationMembershipStats(undefined, machineTypeFilterString);
115	
116	  // ============================================================================
117	  // Computed
118	  // ============================================================================
119	  const financialTotals = useMemo(
120	    () => calculateLocationFinancialTotals(locationData),
121	    [locationData]
122	  );
123	
124	  // Sliced data for the current page
125	  const paginatedLocationData = useMemo(() => {
126	    const startIndex = currentPage * ITEMS_PER_PAGE;
127	    return locationData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
128	  }, [locationData, currentPage, ITEMS_PER_PAGE]);
129	
130	  const isDataMissingForPage = useMemo(() => {
131	    const startIndex = currentPage * ITEMS_PER_PAGE;
132	    const currentBatch = calculateBatchNumber(currentPage);
133	    if (!loadedBatches.has(currentBatch)) {
134	      return true;
135	    }
136	    if (locationData.length <= startIndex && totalCount > locationData.length) {
137	      return loading;
138	    }
139	    return false;
140	  }, [
141	    locationData.length,
142	    currentPage,
143	    ITEMS_PER_PAGE,
144	    totalCount,
145	    loadedBatches,
146	    calculateBatchNumber,
147	    loading,
148	  ]);
149	
150	  const isDataComplete = useMemo(
151	    () => locationData.length >= totalCount && totalCount > 0,
152	    [locationData.length, totalCount]
153	  );
154	
155	  const hasMoreLocations = totalCount > 0 && locationData.length < totalCount;
156	
157	  const effectiveTotalPages = useMemo(() => {
158	    if (hasMoreLocations) {
159	      const loadedBatchCount = Math.ceil(locationData.length / ITEMS_PER_BATCH) || 1;
160	      return loadedBatchCount * PAGES_PER_BATCH;
161	    }
162	    return Math.max(1, Math.ceil(locationData.length / ITEMS_PER_PAGE));
163	  }, [locationData.length, hasMoreLocations, ITEMS_PER_BATCH, ITEMS_PER_PAGE, PAGES_PER_BATCH]);
164	
165	  // ============================================================================
166	  // Handlers
167	  // ============================================================================
168	  const handleRefresh = async () => {
169	    setRefreshing(true);
170	    setCurrentPage(0);
171	    setLoadedBatches(new Set());
172	
173	    // Check and sync SMIB status on refresh
174	    try {
175	      const statusRes = await axios.get<SmibSyncStatus>('/api/admin/smib-sync');
176	      const status = statusRes.data;
177	      if (status.isStale) {
178	        console.log(`[useLocationsPageData] SMIB stale on refresh, syncing...`);
179	        await axios.post('/api/admin/smib-sync', {}, { timeout: 300000 });
180	        console.log('[useLocationsPageData] SMIB sync complete on refresh');
181	      }
182	    } catch (err) {
183	      console.error(
184	        '[useLocationsPageData] SMIB sync check failed on refresh:',
185	        err
186	      );
187	    }
188	
189	    const firstBatch = calculateBatchNumber(0);
190	    setLoadedBatches(new Set([firstBatch]));
191	    await Promise.all([
192	      refreshMachineStats(),
193	      refreshMembershipStats(),
194	      fetchData(firstBatch, ITEMS_PER_BATCH),
195	    ]);
196	    setRefreshing(false);
197	  };
198	
199	  const handleFilterChange = (filter: LocationFilter, checked: boolean) => {
200	    setSelectedFilters(prev =>
201	      checked
202	        ? [...prev, filter]
203	        : prev.filter(activeFilter => activeFilter !== filter)
204	    );
205	    setCurrentPage(0);
206	  };
207	
208	  const handleMultiFilterChange = (filters: LocationFilter[]) => {
209	    setSelectedFilters(filters);
210	    setCurrentPage(0);
211	  };
212	
213	  const handleSort = (option: LocationSortOption) => {
214	    if (sortOption === option) {
215	      setSortOrder(prev => (prev === 'asc' ? 'desc' : 'asc'));
216	    } else {
217	      setSortOption(option);
218	      setSortOrder('desc');
219	    }
220	    setCurrentPage(0);
221	    setLoadedBatches(new Set());
222	  };
223	
224	  // ============================================================================
225	  // Effects
226	  // ============================================================================
227	  useEffect(() => {
228	    if (activeMetricsFilter) {
229	      setFiltersInitialized(true);
230	    }
231	  }, [activeMetricsFilter, setFiltersInitialized]);
232	
233	  // Reset accumulation when filters change
234	  useEffect(() => {
235	    setCurrentPage(0);
236	    setLoadedBatches(new Set());
237	  }, [
238	    selectedFilters,
239	    selectedStatus,
240	    searchTerm,
241	    debouncedSearchTerm,
242	    activeMetricsFilter,
243	    selectedLicencee,
244	    customDateRange,
245	    sortOption,
246	    sortOrder,
247	    displayCurrency,
248	  ]);
249	
250	  // SMIB Auto-Sync on mount (run once when filters are initialized)
251	  useEffect(() => {
252	    if (!filtersInitialized || hasCheckedSmibSync) return;
253	
254	    const checkAndSyncSmib = async () => {
255	      try {
256	        setHasCheckedSmibSync(true);
257	        const statusRes = await axios.get<SmibSyncStatus>(
258	          '/api/admin/smib-sync'
259	        );
260	        const status = statusRes.data;
261	
262	        if (status.isStale) {
263	          console.log(
264	            `[useLocationsPageData] SMIB status stale (last sync: ${status.lastSync}), triggering sync...`
265	          );
266	          await axios.post('/api/admin/smib-sync', {}, { timeout: 300000 });
267	          console.log('[useLocationsPageData] SMIB sync complete');
268	        } else {
269	          console.log(
270	            `[useLocationsPageData] SMIB status fresh (last sync: ${status.lastSync}), skipping sync`
271	          );
272	        }
273	        _setSmibSyncStatus(status);
274	      } catch (err) {
275	        console.error(
276	          '[useLocationsPageData] Failed to check SMIB sync status:',
277	          err
278	        );
279	        setHasCheckedSmibSync(false); // Allow retry on next mount
280	      }
281	    };
282	
283	    void checkAndSyncSmib();
284	  }, [filtersInitialized, hasCheckedSmibSync]);
285	
286	  // Consolidated data fetch effect
287	  useEffect(() => {
288	    if (filtersInitialized) {
289	      const startIndex = currentPage * ITEMS_PER_PAGE;
290	      let targetBatch = calculateBatchNumber(currentPage);
291	
292	      // If we are trying to view a page that is beyond our currently loaded data,
293	      // but the server has more data, we should fetch the next batch.
294	      if (locationData.length <= startIndex && totalCount > locationData.length) {
295	        targetBatch = Math.ceil(locationData.length / ITEMS_PER_BATCH) + 1;
296	      }
297	
298	      if (!loadedBatches.has(targetBatch)) {
299	        console.warn(
300	          `[useLocationsPageData] Fetching batch ${targetBatch} for page ${currentPage + 1}`
301	        );
302	        setLoadedBatches(prev => new Set([...prev, targetBatch]));
303	        void fetchData(targetBatch, ITEMS_PER_BATCH);
304	      }
305	    }
306	  }, [
307	    currentPage,
308	    sortOption,
309	    sortOrder,
310	    selectedFilters,
311	    activeMetricsFilter,
312	    selectedLicencee,
313	    customDateRange,
314	    filtersInitialized,
315	    fetchData,
316	    selectedStatus,
317	    ITEMS_PER_BATCH,
318	    ITEMS_PER_PAGE,
319	    loadedBatches,
320	    calculateBatchNumber,
321	    debouncedSearchTerm, // Added to ensure fetch re-triggers when term settles
322	    locationData.length,
323	    totalCount,
324	  ]);
325	
326	  // Metrics totals fetch
327	  useEffect(() => {
328	    if (!activeMetricsFilter || !filtersInitialized) return;
329	
330	    makeMetricsRequest(async signal => {
331	      setMetricsTotalsLoading(true);
332	      try {
333	        await fetchDashboardTotals(
334	          activeMetricsFilter,
335	          customDateRange || { startDate: new Date(), endDate: new Date() },
336	          selectedLicencee,
337	          data => {
338	            setMetricsTotals(data);
339	          },
340	          displayCurrency,
341	          signal,
342	          machineTypeFilterString,
343	          undefined,
344	          debouncedSearchTerm,
345	          selectedStatus
346	        );
347	      } catch (error) {
348	        // Silently handle aborted requests - this is expected behavior when switching filters
349	        // fetchDashboardTotals should handle abort errors internally, but catch any that leak through
350	        if (isAbortError(error)) {
351	          return;
352	        }
353	        // Re-throw actual errors - fetchDashboardTotals will handle them and show appropriate toasts
354	        throw error;
355	      } finally {
356	        setMetricsTotalsLoading(false);
357	      }
358	    });
359	  }, [
360	    activeMetricsFilter,
361	    selectedLicencee,
362	    customDateRange,
363	    displayCurrency,
364	    filtersInitialized,
365	    machineTypeFilterString,
366	    makeMetricsRequest,
367	    debouncedSearchTerm,
368	    selectedStatus,
369	  ]);
370	
371	  return {
372	    loading:
373	      loading ||
374	      searchLoading ||
375	      isDataMissingForPage ||
376	      searchTerm !== debouncedSearchTerm,
377	    refreshing,
378	    error,
379	    locationData: paginatedLocationData,
380	    financialTotals,
381	    metricsTotals,
382	    metricsTotalsLoading,
383	    machineStats,
384	    machineStatsLoading,
385	    membershipStats,
386	    membershipStatsLoading,
387	    selectedFilters,
388	    selectedStatus,
389	    searchTerm,
390	    currentPage,
391	    totalPages: effectiveTotalPages,
392	    sortOption,
393	    sortOrder,
394	    smibSyncStatus,
395	    // Handlers
396	    handleRefresh,
397	    handleFilterChange,
398	    handleMultiFilterChange,
399	    handleSort,
400	    setSearchTerm,
401	    setCurrentPage,
402	    setSelectedStatus,
403	    fetchData,
404	    totalCount,
405	    hasMoreLocations,
406	    locationDataLength: paginatedLocationData.length,
407	    isDataComplete,
408	  };
409	}
