1	/**
2	 * useLocationChartData Hook
3	 *
4	 * Manages chart data fetching for the location details page.
5	 *
6	 * Features:
7	 * - Chart data fetching with abort controller support
8	 * - Granularity detection (hourly/minute)
9	 * - Data transformation for chart display
10	 * - Request deduplication
11	 */
12	
13	'use client';
14	
15	import { useAbortableRequest } from '@/lib/hooks/useAbortableRequest';
16	import { useCurrencyFormat } from '@/lib/hooks/useCurrencyFormat';
17	import type { dashboardData } from '@/lib/types';
18	import { dateRange as DateRange } from '@/lib/types';
19	import { getDefaultChartGranularity } from '@/lib/utils/chart';
20	import { isAbortError } from '@/lib/utils/errors';
21	
22	import { TimePeriod } from '@/shared/types/common';
23	import axios from 'axios';
24	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
25	
26	type UseLocationChartDataProps = {
27	  locationId: string;
28	  selectedLicencee: string | null;
29	  activeMetricsFilter: TimePeriod | null;
30	  customDateRange: DateRange | null;
31	  activeView: 'machines' | 'members';
32	  status?: string;
33	  gameType?: string;
34	  searchTerm?: string;
35	  includeArchived?: boolean;
36	};
37	
38	export function useLocationChartData({
39	  locationId,
40	  selectedLicencee,
41	  activeMetricsFilter,
42	  customDateRange,
43	  activeView,
44	  status,
45	  gameType,
46	  searchTerm,
47	  includeArchived,
48	}: UseLocationChartDataProps) {
49	  const { displayCurrency } = useCurrencyFormat();
50	  const makeChartRequest = useAbortableRequest();
51	
52	  // ============================================================================
53	  // State & Hooks
54	  // ============================================================================
55	  const [chartData, setChartData] = useState<dashboardData[] | null>(null);
56	  const [loadingChartData, setLoadingChartData] = useState(true);
57	  const [chartGranularity, setChartGranularity] = useState<
58	    'hourly' | 'minute' | 'daily' | 'weekly' | 'monthly'
59	  >(() =>
60	    getDefaultChartGranularity(
61	      activeMetricsFilter || 'Today',
62	      customDateRange?.startDate,
63	      customDateRange?.endDate
64	    )
65	  );
66	  const [availableGranularityOptions, setAvailableGranularityOptions] =
67	    useState<Array<'daily' | 'weekly' | 'monthly'>>([]);
68	
69	  // Ref for tracking manual granularity changes
70	  const hasManuallySetGranularityRef = useRef(false);
71	  // Ref to track the last fetch parameters to prevent unnecessary refetches
72	  const lastFetchParamsRef = useRef<string>('');
73	  // State to force refresh when refresh button is clicked (state triggers re-render)
74	  const [refreshTrigger, setRefreshTrigger] = useState(0);
75	  const [dataSpan, setDataSpan] = useState<{
76	    minDate: string;
77	    maxDate: string;
78	  } | null>(null);
79	
80	  // ============================================================================
81	  // Computed
82	  // ============================================================================
83	  // Show granularity selector for Today/Yesterday/Custom (only if Custom spans ≤ 1 gaming day)
84	  // Also show for Quarterly/All Time if data span >= 1 week
85	  const showGranularitySelector = useMemo(() => {
86	    if (
87	      activeMetricsFilter === 'Today' ||
88	      activeMetricsFilter === 'Yesterday'
89	    ) {
90	      return true;
91	    }
92	    if (
93	      activeMetricsFilter === 'Custom' &&
94	      customDateRange?.startDate &&
