846	          }
847	        }
848	      } finally {
849	        // Only turn off loading if the request completed and wasn't aborted/superseded
850	        if (
851	          cabinetsRequestInProgress.current &&
852	          prevCabinetsFetchKey.current === fetchKey
853	        ) {
854	          setLoading(false);
855	          setCabinetsLoading(false);
856	          cabinetsRequestInProgress.current = false;
857	        }
858	        // Ensure isFilterResetting is always reset when fetching completes or errors
859	        setIsFilterResetting(false);
860	      }
861	    };
862	
863	    fetchData();
864	  }, [
865	    locationId,
866	    selectedLicencee,
867	    activeMetricsFilter,
868	    customDateRange,
869	    dateFilterInitialized,
870	    makeCabinetsRequest,
871	    filtersInitialized,
