880	
881	  // Clear isFilterResetting when new data arrives
882	  useEffect(() => {
883	    if (allCabinets.length > 0) {
884	      setIsFilterResetting(false);
885	    }
886	  }, [allCabinets]);
887	
888	  // Initialize filters flag
