901	    filtersInitialized,
902	    setDateFilterInitialized,
903	    setFiltersInitialized,
904	  ]);
905	
906	  // ============================================================================
907	  // Refresh Handler
908	  // ============================================================================
909	  const refreshCabinets = useCallback(async () => {
910	    setRefreshing(true);
911	    prevCabinetsFetchKey.current = '';
912	    // Trigger refetch by clearing and resetting
913	    setAllCabinets([]);
914	    setAccumulatedCabinets([]);
915	    setLoadedBatches(new Set());
