96	      const nameOnly = searchParams.get('nameOnly') === 'true';
97	      const basicInfo = searchParams.get('basicInfo') === 'true';
98	
99	      if (nameOnly) {
100	        const location = await GamingLocations.findOne(
101	          { _id: locationId },
102	          { _id: 1, name: 1, 'rel.licencee': 1 }
103	        ).lean<LocationDocument>();
104	        if (!location) {
105	          return NextResponse.json(
106	            { success: false, message: 'Not found' },
107	            { status: 404 }
108	          );
109	        }
110	
111	        const licIdRaw = location.rel?.licencee || location.rel?.licencee;
112	        const licIdArr = licIdRaw
113	          ? Array.isArray(licIdRaw) ? licIdRaw : [licIdRaw]
114	          : [];
115	        const includeJackpot = licIdArr.length > 0
116	          ? await fetchLicenceeJackpotFlag(licIdArr[0])
117	          : false;
118	
119	        logRouteFetch(functionName, 'GET', '/api/locations/[locationId]', 1, user, Date.now() - startTime);
120	
121	        return NextResponse.json({
122	          success: true,
123	          location: {
124	            _id: location._id,
125	            name: location.name,
126	            licenceeId: licIdArr,
127	            includeJackpot,
128	          },
129	        });
130	      }
131	
132	      const normalizedRoles = userRoles.map(r => String(r).toLowerCase());
133	      const isAdmin =
134	        normalizedRoles.includes('admin') ||
135	        normalizedRoles.includes('developer') ||
136	        normalizedRoles.includes('owner');
137	      if (!isAdmin && !(await checkUserLocationAccess(locationId))) {
138	        logRouteError(functionName, 'GET', '/api/locations/[locationId]', 'Unauthorized', user);
139	        return NextResponse.json(
140	          { success: false, message: 'Unauthorized' },
141	          { status: 403 }
142	        );
143	      }
144	
145	      const locationCheck = await GamingLocations.findOne({
146	        _id: locationId,
147	      }).lean<LocationDocument>();
148	      if (!locationCheck) {
149	        logRouteError(functionName, 'GET', '/api/locations/[locationId]', 'Not found', user);
150	        return NextResponse.json(
151	          { success: false, message: 'Not found' },
152	          { status: 404 }
153	        );
154	      }
155	
156	      // ============================================================================
157	      // STEP 2: SMIB Auto-Tag (fire-and-forget + in-memory injection)
158	      // ============================================================================
159	      {
160	        const smibTags = await computeAndUpdateSmibTags(locationId, locationCheck.name);
161	        (locationCheck as Record<string, unknown>).fullSMIBs = smibTags.fullSMIBs;
162	        (locationCheck as Record<string, unknown>).semiSMIBs = smibTags.semiSMIBs;
163	        (locationCheck as Record<string, unknown>).noSMIBLocation = smibTags.noSMIBLocation;
164	      }
165	
166	      if (basicInfo || !searchParams.toString().length) {
167	        const includeJackpot = await fetchLicenceeJackpotFlag(locationCheck.rel?.licencee);
168	        logRouteFetch(functionName, 'GET', '/api/locations/[locationId]', 1, user, Date.now() - startTime);
169	        return NextResponse.json({
170	          success: true,
171	          location: { ...locationCheck, includeJackpot },
172	        });
173	      }
174	
175	      // ============================================================================
176	      // STEP 3: Parse Cabinet-List Parameters
177	      // ============================================================================
178	      const licencee = searchParams.get('licencee');
179	      const searchTerm = searchParams.get('search');
180	      const timePeriod = searchParams.get('timePeriod') as TimePeriod;
181	      const customStart = searchParams.get('startDate');
182	      const customEnd = searchParams.get('endDate');
183	      const onlineStatus = searchParams.get('onlineStatus') || 'all';
184	      const smibStatus = (searchParams.get('smibStatus') || 'all').toLowerCase();
185	      const limitParam = searchParams.get('limit');
186	      const limit = limitParam ? parseInt(limitParam) : undefined;
187	      const page = parseInt(searchParams.get('page') || '1');
188	      const skip = limit ? (page - 1) * limit : 0;
189	
190	      if (!timePeriod) {
191	        logRouteError(functionName, 'GET', '/api/locations/[locationId]', 'timePeriod required', user);
192	        return NextResponse.json({ error: 'timePeriod required' }, { status: 400 });
193	      }
194	
195	      if (!isAdmin && licencee && licencee !== 'all') {
196	        const locLicId = locationCheck.rel?.licencee;
197	        if (
198	          locLicId !== licencee &&
199	          (!Array.isArray(locLicId) || !locLicId.includes(licencee))
200	        ) {
201	          logRouteError(functionName, 'GET', '/api/locations/[locationId]', 'Access denied', user);
202	          return NextResponse.json({ error: 'Access denied' }, { status: 403 });
203	        }
204	      }
205	
206	      const gameDayOffset = locationCheck.gameDayOffset ?? 8;
207	      const gdr = getGamingDayRangeForPeriod(
208	        timePeriod,
209	        gameDayOffset,
210	        customStart ? new Date(customStart) : undefined,
211	        customEnd ? new Date(customEnd) : undefined
212	      );
213	
214	      const includeJackpotSetting = await fetchLicenceeJackpotFlag(locationCheck.rel?.licencee);
215	      const { moneyInScale, moneyOutScale } = computeReviewerScales(
216	        userPayload as {
217	          moneyInMultiplier?: number | null;
218	          moneyOutAndJackpotMultiplier?: number | null;
219	          roles?: string[];
220	          reviewerMultiplierStartTime?: Date | string | null;
221	        },
222	        gdr.rangeEnd
223	      );
224	
225	      // ============================================================================
226	      // STEP 4: Build Machine Filter and Fetch Machines
227	      // ============================================================================
228	      const includeArchived = searchParams.get('includeArchived') === 'true';
229	      const mMatch = buildMachinesFilter({
230	        locationId,
231	        includeArchived,
232	        onlineStatus,
233	        smibStatus,
234	        aceEnabled: !!locationCheck.aceEnabled,
235	      });
236	
237	      const machines = await Machine.find(mMatch, {
238	        _id: 1,
239	        serialNumber: 1,
240	        relayId: 1,
241	        smibBoard: 1,
242	        'custom.name': 1,
243	        lastActivity: 1,
244	        game: 1,
245	        manufacturer: 1,
246	        manuf: 1,
247	        cabinetType: 1,
248	        gameType: 1,
249	        isCronosMachine: 1,
250	        sasMeters: 1,
251	        assetStatus: 1,
252	        deletedAt: 1,
253	        'meta.dataSync.source': 1,
254	      }).lean<GamingMachine[]>();
255	
256	      if (!machines.length) {
257	        logRouteFetch(functionName, 'GET', '/api/locations/[locationId]', 0, user, Date.now() - startTime);
258	        return NextResponse.json({
259	          success: true,
260	          data: [],
261	          pagination: {
262	            page: 1,
263	            limit: limit || 0,
264	            total: 0,
265	            totalPages: 0,
266	            hasNextPage: false,
267	            hasPrevPage: false,
268	          },
269	        });
270	      }
271	
272	      // ============================================================================
273	      // STEP 5: Search Filter, Aggregate Metrics, Map to Cabinet Items
274	      // ============================================================================
275	      const filteredMachines = searchTerm
276	        ? filterMachinesBySearch(machines, searchTerm)
277	        : machines;
278	
279	      const filteredMachineIds = filteredMachines.map(m => String(m._id));
280	      const metricsRecords = await fetchMachineMetrics(
281	        locationId,
282	        filteredMachineIds,
283	        gdr.rangeStart,
284	        gdr.rangeEnd
285	      );
286	      const metricsMap = buildMetricsMap(metricsRecords);
287	
288	      const mappingContext: CabinetMappingContext = {
289	        locationId,
290	        locationName: locationCheck.name || 'Location',
291	        aceEnabled: !!locationCheck.aceEnabled,
292	        moneyInScale,
293	        moneyOutScale,
294	        includeJackpotSetting,
295	      };
296	      const cabinetItems: CabinetItemData[] = mapMachinesToCabinetData(
297	        filteredMachines,
298	        metricsMap,
299	        mappingContext
300	      );
301	
302	      // ============================================================================
303	      // STEP 6: Sort, Paginate, Transform, Respond
304	      // ============================================================================
305	      sortCabinetData(cabinetItems, searchTerm || undefined);
306	      const result = paginateAndTransformCabinets(cabinetItems, page, limit, skip);
307	
308	      logRouteFetch(functionName, 'GET', '/api/locations/[locationId]', result.data.length, user, Date.now() - startTime);
309	
310	      return NextResponse.json({
311	        success: true,
312	        data: result.data,
313	        pagination: result.pagination,
314	      });
315	    } catch (error: unknown) {
316	      const message = error instanceof Error ? error.message : 'Unknown error';
317	      logRouteError(functionName, 'GET', '/api/locations/[locationId]', message, user);
318	      console.error('[Location Detail API] Error:', error);
319	      return NextResponse.json({ error: message }, { status: 500 });
320	    }
321	  });
322	}
