1239	              $ifNull: [
1240	                { $arrayElemAt: ['$machineData.latestActivity', 0] },
1241	                0,
1242	              ],
1243	            },
1244	            wowMachines: {
1245	              $ifNull: [{ $arrayElemAt: ['$machineData.wowMachines', 0] }, 0],
1246	            },
1247	            isWowLocation: {
1248	              $gt: [
1249	                { $ifNull: [{ $arrayElemAt: ['$machineData.wowMachines', 0] }, 0] },
1250	                0,
1251	              ],
1252	            },
1253	            gross: { $subtract: ['$moneyIn', '$moneyOut'] },
1254	          },
1255	        },
1256	        // Add SAS evaluation filter if requested
1257	        // For basic lists, we need to filter SAS locations after machine lookup
1258	        // For detailed queries, we can filter after financial aggregation
1259	        ...(sasEvaluationOnly
1260	          ? [
1261	              {
1262	                $match: {
1263	                  sasMachines: { $gt: 0 },
1264	                },
1265	              },
1266	            ]
1267	          : []),
1268	      ],
1269	      {
1270	        allowDiskUse: true,
1271	        maxTimeMS: 60000, // Increased to 60 seconds for complex aggregations
1272	      }
1273	    ).exec();
1274	
1275	    // Transform the aggregated data to the expected format
1276	    const enhancedMetrics = locationsWithMetrics.map(location => {
1277	      const locationId = location._id.toString();
1278	
1279	      // Calculate metrics with proper fallbacks
1280	      const moneyIn = location.moneyIn || 0;
1281	      const moneyOut = location.moneyOut || 0;
1282	      const gross = location.gross || moneyIn - moneyOut;
1283	
1284	      // Additional meter fields
1285	      const coinIn = location.coinIn || 0;
1286	      const coinOut = location.coinOut || 0;
1287	      const jackpot = location.jackpot || 0;
1288	
1289	      // Machine counts with proper fallbacks
1290	      const totalMachines = location.totalMachines || 0;
1291	      const onlineMachines = location.aceEnabled
1292	        ? totalMachines
1293	        : location.onlineMachines || 0;
1294	      const sasMachines = location.sasMachines || 0;
1295	      const nonSasMachines = location.nonSasMachines || 0;
1296	      const gamesPlayed = location.gamesPlayed || 0;
1297	
1298	      // Determine if location has SAS machines
1299	      const hasSasMachines = sasMachines > 0;
1300	      const hasNonSasMachines = nonSasMachines > 0;
1301	
1302	      return {
1303	        location: locationId,
1304	        locationName: location.name || 'Unknown Location',
1305	        moneyIn,
1306	        moneyOut,
1307	        gross,
1308	        coinIn,
1309	        coinOut,
1310	        jackpot,
1311	        totalMachines,
1312	        onlineMachines,
1313	        sasMachines,
1314	        nonSasMachines,
1315	        hasSasMachines,
1316	        hasNonSasMachines,
1317	        isLocalServer: location.isLocalServer || false,
1318	        noSMIBLocation: !hasSasMachines,
1319	        hasSmib: hasSasMachines,
1320	        isWowLocation: (location.wowMachines || 0) > 0,
1321	        gamesPlayed,
1322	        isNeverOnline:
1323	          totalMachines > 0 && (location.hasActivityCount || 0) === 0,
1324	        latestActivity: location.latestActivity
1325	          ? new Date(location.latestActivity).getTime()
1326	          : 0,
1327	      } as unknown as AggregatedLocation;
1328	    });
1329	
1330	    // ============================================================================
1331	    // Mark NON-SMIB locations as offline if no collection report in past 3 months
1332	    // WOW locations are always online — exclude them from this override.
1333	    // ============================================================================
1334	    const nonSmibLocations = enhancedMetrics.filter(
1335	      loc =>
1336	        !(loc as AggregatedLocation & { isWowLocation?: boolean })
1337	          .isWowLocation &&
1338	        (loc.sasMachines === 0 || loc.noSMIBLocation)
1339	    );
1340	
1341	    if (nonSmibLocations.length > 0) {
1342	      const { CollectionReport } =
1343	        await import('@/app/api/lib/models/collectionReport');
1344	
1345	      // Calculate date 3 months ago
1346	      const threeMonthsAgo = new Date();
1347	      threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);
1348	
1349	      // Get collection reports for NON-SMIB locations in the past 3 months
1350	      const nonSmibLocationIds = nonSmibLocations.map(loc => loc.location);
1351	      const recentCollectionReports = await CollectionReport.find({
1352	        location: { $in: nonSmibLocationIds },
1353	        timestamp: { $gte: threeMonthsAgo },
1354	      })
1355	        .select('location timestamp')
1356	        .lean<CollectionReportDocument[]>();
1357	
1358	      // Create a set of location IDs that have recent collection reports
1359	      const locationsWithRecentReports = new Set<string>();
1360	      recentCollectionReports.forEach(
1361	        (collectionReport: { location: string }) => {
1362	          locationsWithRecentReports.add(collectionReport.location);
1363	        }
1364	      );
1365	
1366	      // Mark locations without recent collection reports as offline
1367	      // Also add flag to indicate missing collection report
1368	      enhancedMetrics.forEach(locationMetric => {
1369	        const isWow = (
1370	          locationMetric as AggregatedLocation & { isWowLocation?: boolean }
1371	        ).isWowLocation;
1372	        if (
1373	          !isWow &&
1374	          (locationMetric.sasMachines === 0 || locationMetric.noSMIBLocation) &&
1375	          !locationsWithRecentReports.has(locationMetric.location)
1376	        ) {
1377	          // No collection report in past 3 months - mark as offline
1378	          locationMetric.onlineMachines = 0;
1379	          // Add flag for frontend to show warning icon
1380	          (
1381	            locationMetric as { hasNoRecentCollectionReport?: boolean }
1382	          ).hasNoRecentCollectionReport = true;
1383	        }
1384	      });
1385	    }
1386	
1387	    // ============================================================================
1388	    // STEP 10: Apply online status filter if requested
1389	    // ============================================================================
1390	    let filteredByStatus = enhancedMetrics;
1391	    if (onlineStatus && onlineStatus !== 'all') {
1392	      filteredByStatus = enhancedMetrics.filter(loc => {
1393	        const isOnline = loc.onlineMachines > 0;
1394	
1395	        if (onlineStatus === 'online') {
1396	          return isOnline;
1397	        }
1398	
1399	        if (onlineStatus.startsWith('offline')) {
1400	          return !isOnline && loc.totalMachines > 0;
1401	        }
1402	
1403	        if (onlineStatus === 'neveronline') {
1404	          return (loc as AggregatedLocation & { isNeverOnline?: boolean })
1405	            .isNeverOnline;
1406	        }
1407	
1408	        return true;
1409	      });
1410	    }
1411	
1412	    const allResults = filteredByStatus;
1413	
1414	    // Decide whether to paginate. For basic lists (page-load dropdown) and for
1415	    // explicit selectedLocations queries, return ALL rows without slicing.
1416	    const shouldPaginate = !(basicList || selectedLocations);
1417	
1418	    const totalCount = allResults.length;
1419	    const startIndex = shouldPaginate ? (page - 1) * limit : 0;
1420	    const endIndex = shouldPaginate ? startIndex + limit : totalCount;
1421	    const outputRows = allResults.slice(startIndex, endIndex);
1422	
1423	    return {
1424	      rows: outputRows,
1425	      totalCount,
1426	    };
1427	  }
1428	};
