124	// ============================================================================
125	// 1. SMIB Auto-Tag
126	// ============================================================================
127	
128	/**
129	 * Computes SMIB classification (fullSMIBs / semiSMIBs / noSMIBLocation) for
130	 * a location based on its active machines' relayId presence. Updates the DB
131	 * record and returns the computed flags for immediate response use.
132	 */
133	export async function computeAndUpdateSmibTags(
134	  locationId: string,
135	  locationName: string
136	): Promise<SmibTagResult> {
137	  const activeMachinesForTag = await Machine.find(
138	    {
139	      gamingLocation: locationId,
140	      $or: [
141	        { deletedAt: null },
142	        { deletedAt: { $lt: DELETION_SOFT_CUTOFF } },
143	      ],
144	    },
145	    { _id: 1, relayId: 1, 'meta.dataSync.source': 1 }
146	  ).lean<{ _id: string; relayId?: string; meta?: { dataSync?: { source?: string } } }[]>();
147	
148	  const totalForTag = activeMachinesForTag.length;
149	  const withRelayForTag = activeMachinesForTag.filter(
150	    m =>
151	      (m.relayId && String(m.relayId).trim()) || isWowMachine(m as Parameters<typeof isWowMachine>[0])
152	  ).length;
153	  const withoutRelayForTag = totalForTag - withRelayForTag;
154	
155	  const computedFull = totalForTag > 0 && withRelayForTag === totalForTag;
156	  const computedSemi =
157	    totalForTag > 0 && withRelayForTag > 0 && withRelayForTag < totalForTag;
158	  const computedNone = !computedFull && !computedSemi;
159	
160	  const computedType = computedFull
161	    ? 'fullSMIBs'
162	    : computedSemi
163	      ? 'semiSMIBs'
164	      : 'noSMIBLocation';
165	
166	  console.log(
167	    `[GET /api/locations/[locationId]] SMIB check for "${locationName}" (${locationId}) — ` +
168	      `total machines: ${totalForTag}, with relayId: ${withRelayForTag}, without relayId: ${withoutRelayForTag} → computed: ${computedType}`
169	  );
170	
171	  GamingLocations.updateOne(
172	    { _id: locationId },
173	    {
174	      $set: {
175	        fullSMIBs: computedFull,
176	        semiSMIBs: computedSemi,
177	        noSMIBLocation: computedNone,
178	      },
179	    }
180	  )
181	    .then(result => {
182	      console.log(
183	        `[GET /api/locations/[locationId]] "${locationName}" — update complete, modified: ${result.modifiedCount}`
184	      );
185	    })
186	    .catch(err => {
187	      console.error(
188	        `[GET /api/locations/[locationId]] "${locationName}" — update failed:`,
189	        err
190	      );
191	    });
192	
193	  return { fullSMIBs: computedFull, semiSMIBs: computedSemi, noSMIBLocation: computedNone };
194	}
