200	/**
201	 * Resolves the includeJackpot setting from a location's licencee reference.
202	 * Accepts a single licencee ID or array (uses first element).
203	 */
204	export async function fetchLicenceeJackpotFlag(
205	  locLicId: string | string[] | undefined
206	): Promise<boolean> {
207	  if (!locLicId) return false;
208	  const licenceeId = Array.isArray(locLicId) ? locLicId[0] : locLicId;
209	  if (!licenceeId) return false;
210	  const licDoc = await Licencee.findOne(
211	    { _id: licenceeId },
212	    { includeJackpot: 1 }
