217	// ============================================================================
218	// 3. Build Machine Filter for Cabinets List
219	// ============================================================================
220	
221	/**
222	 * Builds a MongoDB query filter for fetching machines belonging to a location.
223	 * Applies archive, online-status, and SMIB-status filters conditionally.
224	 */
225	export function buildMachinesFilter(params: CabinetsFilterParams): Record<string, unknown> {
226	  const mMatch: Record<string, unknown> = {
227	    $and: [{ gamingLocation: params.locationId }] as unknown[],
228	  };
229	  const andConditions = mMatch.$and as unknown[];
230	
231	  if (!params.includeArchived) {
232	    andConditions.push({
233	      $or: [
234	        { deletedAt: null },
235	        { deletedAt: { $lt: DELETION_SOFT_CUTOFF } },
236	      ],
237	    });
238	  } else {
239	    andConditions.push({
240	      $or: [{ deletedAt: null }, { deletedAt: { $exists: true } }],
241	    });
242	  }
243	
244	  if (params.onlineStatus !== 'all') {
245	    const threeMin = new Date(Date.now() - CABINET_ONLINE_THRESHOLD_MS);
246	    if (params.aceEnabled) {
247	      if (params.onlineStatus === 'online') {
248	        // All active machines are online in ACE locations
249	      } else if (params.onlineStatus === 'offline' || params.onlineStatus === 'never-online') {
250	        andConditions.push({ _id: null });
251	      }
252	    } else {
253	      if (params.onlineStatus === 'online') {
254	        (mMatch as Record<string, unknown>).lastActivity = { $gte: threeMin };
255	      } else if (params.onlineStatus === 'offline') {
256	        andConditions.push({
257	          $or: [
258	            { lastActivity: { $lt: threeMin } },
259	            { lastActivity: { $exists: false } },
260	            { lastActivity: null },
261	          ],
262	        });
263	      } else if (params.onlineStatus === 'never-online') {
264	        andConditions.push({
265	          $or: [
266	            { lastActivity: { $exists: false } },
267	            { lastActivity: null },
268	          ],
269	        });
270	      }
271	    }
272	  }
273	
274	  if (params.smibStatus !== 'all') {
275	    if (params.smibStatus === 'smib') {
276	      andConditions.push({
277	        $or: [
278	          { relayId: { $ne: '', $exists: true, $not: /^\s*$/ } },
279	          { smibBoard: { $ne: '', $exists: true, $not: /^\s*$/ } },
280	        ],
281	      });
282	    } else if (params.smibStatus === 'no-smib') {
283	      andConditions.push({
284	        $and: [
285	          {
286	            $or: [
287	              { relayId: '' },
288	              { relayId: null },
289	              { relayId: { $exists: false } },
290	              { relayId: /^\s*$/ },
291	            ],
292	          },
293	          {
294	            $or: [
295	              { smibBoard: '' },
296	              { smibBoard: null },
297	              { smibBoard: { $exists: false } },
298	              { smibBoard: /^\s*$/ },
299	            ],
300	          },
301	        ],
302	      });
303	    }
304	  }
305	
306	  return mMatch;
307	}
