313	/**
314	 * Computes reviewer moneyIn and moneyOut scales for the time period.
315	 * Returns { moneyInScale: number; moneyOutScale: number } with values
316	 * between 0 and 1 (1 = no scaling).
317	 */
318	export function computeReviewerScales(
319	  userPayload: {
320	    moneyInMultiplier?: number | null;
321	    moneyOutAndJackpotMultiplier?: number | null;
322	    roles?: string[];
323	    reviewerMultiplierStartTime?: Date | string | null;
324	  },
325	  rangeEnd: Date
326	): { moneyInScale: number; moneyOutScale: number } {
327	  const moneyInScale = getMoneyInScale(userPayload, rangeEnd);
328	  const moneyOutScale = getMoneyOutAndJackpotScale(userPayload, rangeEnd);
329	  return { moneyInScale, moneyOutScale };
330	}
