332	// ============================================================================
333	// 5. Fetch Machine Metrics with Cursor
334	// ============================================================================
335	
336	/**
337	 * Aggregates meter data for the given machine IDs and time range.
338	 * Uses cursor-based iteration for large result sets.
339	 */
340	export async function fetchMachineMetrics(
341	  locationId: string,
342	  machineIds: string[],
343	  rangeStart: Date,
344	  rangeEnd: Date
345	): Promise<MachineMetricsRecord[]> {
346	  const rawMachineMetrics: MachineMetricsRecord[] = [];
347	  const cursor = Meters.aggregate([
348	    {
349	      $match: {
350	        $and: [
351	          { location: locationId },
352	          { machine: { $in: machineIds } },
353	          { readAt: { $gte: rangeStart, $lte: rangeEnd } },
354	        ],
355	      },
356	    },
357	    {
358	      $group: {
359	        _id: '$machine',
360	        moneyIn: { $sum: '$movement.drop' },
361	        moneyOut: { $sum: '$movement.totalCancelledCredits' },
362	        jackpot: { $sum: '$movement.jackpot' },
363	        gamesPlayed: { $sum: '$movement.gamesPlayed' },
364	        gamesWon: { $sum: '$movement.gamesWon' },
365	      },
366	    },
367	    { $addFields: { gross: { $subtract: ['$moneyIn', '$moneyOut'] } } },
368	  ]).cursor({ batchSize: 1000 });
369	
370	  for await (const doc of cursor) {
371	    rawMachineMetrics.push(doc as MachineMetricsRecord);
372	  }
373	
374	  return rawMachineMetrics;
375	}
