377	/**
378	 * Converts a raw metrics array into a Map keyed by machine _id for O(1) lookup.
379	 */
380	export function buildMetricsMap(
381	  records: MachineMetricsRecord[]
382	): MachineMetricsMap {
383	  const map: MachineMetricsMap = new Map();
384	  for (const record of records) {
385	    map.set(String(record._id), {
386	      moneyIn: record.moneyIn,
387	      moneyOut: record.moneyOut,
388	      gross: record.gross,
389	      jackpot: record.jackpot,
390	      gamesPlayed: record.gamesPlayed,
391	      gamesWon: record.gamesWon,
392	    });
393	  }
394	  return map;
395	}
