397	// ============================================================================
398	// 6. Map Machines to Cabinet Items
399	// ============================================================================
400	
401	/**
402	 * Maps raw GamingMachine documents + aggregated metrics into CabinetItemData
403	 * objects with computed financials and online status.
404	 */
405	export function mapMachinesToCabinetData(
406	  machines: GamingMachine[],
407	  metricsMap: MachineMetricsMap,
408	  context: CabinetMappingContext
409	): CabinetItemData[] {
410	  return machines.map(machine => {
411	    const currentMachineId = String(machine._id);
412	    const machineMeters = metricsMap.get(currentMachineId) || {
413	      moneyIn: 0,
414	      moneyOut: 0,
415	      gross: 0,
416	      jackpot: 0,
417	      gamesPlayed: 0,
418	      gamesWon: 0,
419	    };
420	    const serialNumber = (machine.serialNumber as string)?.trim() || '';
421	    const customName =
422	      ((machine.custom as unknown as { name?: string })?.name as string)?.trim() || '';
423	    const assetNumber = serialNumber || customName || '';
424	    const lastActivityDate = machine.lastActivity as Date | null;
425	    // WOW machines have no SMIB/relay but are always treated as online.
426	    const isOnline =
427	      isWowMachine(machine) ||
428	      context.aceEnabled ||
429	      (lastActivityDate &&
430	        new Date(lastActivityDate) > new Date(Date.now() - CABINET_ONLINE_THRESHOLD_MS));
431	    const rawMoneyIn = (Number(machineMeters.moneyIn) || 0) * context.moneyInScale;
432	    const rawMoneyOut = (Number(machineMeters.moneyOut) || 0) * context.moneyOutScale;
433	    const rawJackpot = (Number(machineMeters.jackpot) || 0) * context.moneyOutScale;
434	    const adjustedMoneyOut = rawMoneyOut + (context.includeJackpotSetting ? rawJackpot : 0);
435	    const grossProfit = rawMoneyIn - adjustedMoneyOut;
436	
437	    return {
438	      _id: currentMachineId,
439	      locationId: context.locationId,
440	      locationName: context.locationName,
441	      assetNumber,
442	      serialNumber: assetNumber,
443	      custom: (machine.custom || {}) as Record<string, unknown>,
444	      relayId: (machine.relayId as string) || '',
445	      smibBoard: (machine.smibBoard as string) || '',
446	      smbId: (machine.smibBoard as string) || (machine.relayId as string) || '',
447	      lastActivity: lastActivityDate,
448	      lastOnline: lastActivityDate,
449	      game: (machine.game as string) || '',
450	      installedGame: (machine.game as string) || '',
451	      manufacturer:
452	        (machine.manufacturer as string) || (machine.manuf as string) || 'Unknown',
453	      cabinetType: (machine.cabinetType as string) || '',
454	      status: (machine.assetStatus as string) || '',
455	      gameType: (machine.gameType as string) || '',
456	      isCronosMachine: !!machine.isCronosMachine,
457	      moneyIn: rawMoneyIn,
458	      moneyOut: adjustedMoneyOut,
459	      gross: grossProfit,
460	      jackpot: rawJackpot,
461	      gamesPlayed: Number(machineMeters.gamesPlayed) || 0,
462	      gamesWon: Number(machineMeters.gamesWon) || 0,
463	      cancelledCredits: adjustedMoneyOut,
464	      sasMeters: (machine.sasMeters || null) as Record<string, unknown> | null,
465	      online: !!isOnline,
466	      includeJackpot: context.includeJackpotSetting,
467	      deletedAt: (machine as unknown as { deletedAt?: Date }).deletedAt || null,
468	      meta: machine.meta,
469	    };
470	  });
471	}
472	
473	// ============================================================================
474	// 7. Sort Cabinet Items
475	// ============================================================================
476	
477	/**
478	 * Multi-level sort: search prefix relevance → online status → gross descending → serial number.
479	 * Mutates the array in place.
480	 */
481	export function sortCabinetData(
482	  items: CabinetItemData[],
483	  searchTerm?: string
484	): void {
485	  items.sort((a, b) => {
486	    if (searchTerm) {
487	      const lowerSearch = searchTerm.toLowerCase();
488	      const aStarts = a.serialNumber.toLowerCase().startsWith(lowerSearch);
489	      const bStarts = b.serialNumber.toLowerCase().startsWith(lowerSearch);
490	      if (aStarts && !bStarts) return -1;
491	      if (!aStarts && bStarts) return 1;
492	    }
493	
494	    if (a.online && !b.online) return -1;
495	    if (!a.online && b.online) return 1;
496	
497	    const bGross = Number(b.gross) || 0;
498	    const aGross = Number(a.gross) || 0;
499	    if (bGross !== aGross) return bGross - aGross;
500	
501	    return a.serialNumber.localeCompare(b.serialNumber);
502	  });
503	}
504	
505	// ============================================================================
506	// 8. Paginate and Transform to TransformedCabinet
507	// ============================================================================
508	
509	/**
510	 * Applies pagination slicing and transforms CabinetItemData to TransformedCabinet
511	 * (adds netGross and metersData fields).
512	 */
513	export function paginateAndTransformCabinets(
514	  items: CabinetItemData[],
515	  page: number,
516	  limit: number | undefined,
517	  skip: number
518	): PaginatedCabinetResult {
519	  const total = items.length;
520	  const paginated = limit ? items.slice(skip, skip + limit) : items;
521	
522	  const data: TransformedCabinet[] = paginated.map(item => {
523	    const currentGross = Number(item.gross) || 0;
524	    const currentJackpot = Number(item.jackpot) || 0;
525	    return {
526	      ...item,
527	      netGross: item.includeJackpot ? currentGross - currentJackpot : undefined,
528	      metersData: null,
529	    } as unknown as TransformedCabinet;
530	  });
531	
532	  const totalPages = limit ? Math.ceil(total / limit) : 1;
533	
534	  return {
535	    data,
536	    pagination: {
537	      page,
538	      limit: limit || total,
539	      total,
540	      totalPages,
541	      hasNextPage: limit ? page < totalPages : false,
542	      hasPrevPage: page > 1,
543	    },
544	  };
545	}
546	
547	// ============================================================================
548	// 9. Filter Machines by Search Term
549	// ============================================================================
550	
551	/**
552	 * Filters machines array by search term (case-insensitive match on
553	 * serialNumber, relayId, smibBoard, custom name, or _id).
554	 */
555	export function filterMachinesBySearch(
556	  machines: GamingMachine[],
557	  searchTerm: string
558	): GamingMachine[] {
559	  const lowerSearchTerm = searchTerm.toLowerCase();
560	  return machines.filter(
561	    machine =>
562	      machine.serialNumber?.toLowerCase().includes(lowerSearchTerm) ||
563	      machine.relayId?.toLowerCase().includes(lowerSearchTerm) ||
564	      machine.smibBoard?.toLowerCase().includes(lowerSearchTerm) ||
565	      ((machine.custom as unknown as { name?: string })?.name || '')
566	        .toLowerCase()
567	        .includes(lowerSearchTerm) ||
568	      String(machine._id).toLowerCase().includes(lowerSearchTerm)
569	  );
570	}
