1	/**
2	 * Membership Count API Route
3	 *
4	 * This route returns the count of locations with membership enabled.
5	 *
6	 * @module app/api/locations/membership-count/route
7	 */
8	
9	import {
10	  getUserAccessibleLicenceesFromToken,
11	  getUserLocationFilter,
12	} from '@/app/api/lib/helpers/licenceeFilter';
13	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
14	import { connectDB } from '@/app/api/lib/middleware/db';
15	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
16	import {
17	  logRouteFetch,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	import { NextRequest, NextResponse } from 'next/server';
22	
23	/**
24	 * Main GET handler for membership count
25	 *
26	 * @param {string} licencee - Filter count by licencee name
27	 * @param {string} locationId - Filter count by specific location ID
28	 *
29	 * Flow:
30	 * 1. Parse licencee parameter
31	 * 2. Connect to database and authenticate user
32	 * 3. Get user location permissions
33	 * 4. Count locations with membership enabled
34	 * 5. Return count
35	 */
36	export async function GET(req: NextRequest) {
37	  const startTime = Date.now();
38	  const functionName = 'GET /api/locations/membership-count';
39	  const logUser = extractUserFromRequest(req);
40	
41	  try {
42	    // ============================================================================
43	    // STEP1: Parse request parameters
44	    // ============================================================================
45	    const { searchParams } = new URL(req.url);
46	    const licencee = searchParams.get('licencee');
47	    const locationId = searchParams.get('locationId');
48	
49	    // ============================================================================
50	    // STEP 2: Connect to database and authenticate user
51	    // ============================================================================
52	    const db = await connectDB();
53	    if (!db) {
54	      return NextResponse.json(
55	        { error: 'Database connection failed', membershipCount: 0 },
56	        { status: 500 }
57	      );
58	    }
59	
60	    const user = await getUserFromServer();
61	
62	    // Get user's accessible licencees
63	    const userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
64	
65	    // Get user's location permissions and roles
66	    const userLocationPermissions = ((
67	      user?.resourcePermissions as
68	        | Record<
69	            string,
70	            {
71	              resources?: Array<{ _id: string }>;
72	            }
73	          >
74	        | undefined
75	    )?.['gaming-locations']?.resources?.map(
76	      (resource: { _id: string }) => resource._id
77	    ) || []) as string[];
78	    const userRoles = (user?.roles || []) as string[];
79	
80	    // ============================================================================
81	    // STEP 3: Get user location permissions
82	    // ============================================================================
83	    const allowedLocationIds = await getUserLocationFilter(
84	      userAccessibleLicencees,
85	      licencee || undefined,
86	      userLocationPermissions,
87	      userRoles
88	    );
89	
90	    // ============================================================================
91	    // STEP 4: Build query for membership-enabled locations
92	    // ============================================================================
93	    const query: Record<string, unknown> = {
94	      $and: [
95	        {
96	          $or: [
97	            { deletedAt: null },
98	            { deletedAt: { $lt: new Date('2025-01-01') } },
99	          ],
100	        },
101	        // Check both membershipEnabled and enableMembership fields for compatibility
102	        {
103	          $or: [{ membershipEnabled: true }, { enableMembership: true }],
104	        },
105	      ],
106	    };
107	
108	    // Apply location permissions
109	    if (allowedLocationIds !== 'all') {
110	      if (allowedLocationIds.length === 0) {
111	        return NextResponse.json({ membershipCount: 0 });
112	      }
113	      query._id = { $in: allowedLocationIds };
114	    }
115	
116	    // Apply licencee filter if provided
117	    if (licencee && licencee !== 'all') {
118	      query['rel.licencee'] = licencee;
119	    }
120	
121	    // Apply specific location filter if provided
122	    if (locationId) {
123	      query._id = locationId;
124	    }
125	
126	    // ============================================================================
127	    // STEP 5: Count locations with membership enabled
128	    // ============================================================================
129	    const membershipCount = await GamingLocations.countDocuments(query);
130	
131	    const duration = Date.now() - startTime;
132	    logRouteFetch(
133	      functionName,
134	      'GET',
135	      '/api/locations/membership-count',
136	      1,
137	      logUser,
138	      duration
139	    );
140	
141	    return NextResponse.json({ membershipCount });
142	  } catch (err) {
143	    const errorMessage = err instanceof Error ? err.message : 'Server Error';
144	    logRouteError(
145	      functionName,
146	      'GET',
147	      '/api/locations/membership-count',
148	      errorMessage,
149	      logUser
150	    );
151	    console.error('[API Error] Membership count:', errorMessage);
152	    return NextResponse.json(
153	      { error: errorMessage, membershipCount: 0 },
154	      { status: 500 }
155	    );
156	  }
157	}
